const json = $json;
const history = (json.status_history && json.status_history.data && json.status_history.data.shipping_history && json.status_history.data.shipping_history.events) || [];
const code = json.shipping_status_code;
let baseDate = new Date(json.shipping_status_datetime);

// Lógica de Tránsito Unificada (0900 + 1000)
if (code === '0900' || code === '1000') {
    const transitEvents = history.filter(e => e.type === 'STATUS' && (e.code === '0900' || e.code === '1000'));
    if (transitEvents.length > 0) {
        // Ordenar por fecha y coger la PRIMERA detección
        transitEvents.sort((a, b) => new Date(a.event_date) - new Date(b.event_date));
        baseDate = new Date(transitEvents[0].event_date);
    }
}

const now = new Date();
let count = 0;
if (baseDate instanceof Date && !isNaN(baseDate.getTime()) && baseDate < now) {
    let cur = new Date(baseDate);
    while (cur < now) {
        // Solo sumamos horas en días laborables (L-V)
        if (cur.getDay() !== 0 && cur.getDay() !== 6) count++;
        cur.setHours(cur.getHours() + 1);
    }
}

return {
    ...json,
    hours_in_status: count
};

